ControlPropertyState.AutoRuleBindingString:
With(
    {
        varExpandedSidebar: 390 * Power(OpenSidebar_Timer.Value / OpenSidebar_Timer.Duration, 0.3), //0+(OpenSidebar_Timer.Value)*0.8,

        varCollapsedSidebar: 390 * Power((CloseSidebar_Timer.Duration - CloseSidebar_Timer.Value) / CloseSidebar_Timer.Duration, 2) //280 - (CloseSidebar_Timer.Value)*0.8
    },
    Switch(
        cmpNavbarSidebar.IsMenuOpen,
        true, varExpandedSidebar,       // Cuando el input está seleccionado, el Label sube a Y = 0
        false, varCollapsedSidebar,     // Cuando el input pierde el foco, el Label vuelve a su posición original
        390                             // Valor por defecto
    )
)
